        case ROUP_CLAUSE_INBRANCH:      return OMPC_inbranch;
        case ROUP_CLAUSE_NOTINBRANCH:   return OMPC_notinbranch;
        case ROUP_CLAUSE_DIST_SCHEDULE: return OMPC_dist_schedule;
