        case ROUP_CLAUSE_INITIALIZER:   return OMPC_initializer;
        case ROUP_CLAUSE_FINAL:         return OMPC_final;
        case ROUP_CLAUSE_UNTIED:        return OMPC_untied;
        case ROUP_CLAUSE_REQUIRES:      return OMPC_requires;
        case ROUP_CLAUSE_MERGEABLE:     return OMPC_mergeable;
        case ROUP_CLAUSE_IN_REDUCTION:  return OMPC_in_reduction;
        case ROUP_CLAUSE_DEPEND:        return OMPC_depend;
        case ROUP_CLAUSE_PRIORITY:      return OMPC_priority;
